"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[3407],{4105(e){e.exports=JSON.parse('{"slug":"rosette1","title":"Caldwell 49 Rosette Nebula","date":"2026-02","year":null,"featuredRank":1,"thumb":"/img/gallery/_gen/rosette1-thumb.jpg","image":"/img/gallery/_gen/rosette1-full.jpg","aspect":1.6125323368784132,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/rosette1.jpg","source":"@site/gallery/rosette1.mdx","sourceFilePath":"gallery/rosette1.mdx","_content":"\\nFirst time trying the C49 Rosette Nebula. This time I was able to see Polaris, so I polar aligned with the laser, which turns out can do 20s subs pretty fine.\\n\\nStock EOS R8, RF 70-200 f4 L IS USM @ 200mm f4, 300x 20s ISO 1600. Processed in PixInsight. First time using PixInsight, it was honestly quite easy to learn, and this is the second edit, which I used a masked stretch to preserve blue in the centre, but it makes it much brighter. I would prefer having more blue/cyan in the centre more though.\\n\\nPixInsight brought out so much detail compared to Siril with Darktable. Taken in Bortle 4/5."}')}}]);